CREATE TABLE IF NOT EXISTS products (id BIGINT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120) NOT NULL, category VARCHAR(60) NOT NULL, price DECIMAL(10,2) NOT NULL, stock INT NOT NULL, description VARCHAR(500) NOT NULL, image_url VARCHAR(300) NOT NULL, featured BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP); -- 创建商品表用于 MyBatis 和 MyBatis-Plus。 
CREATE TABLE IF NOT EXISTS customers (id BIGINT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(80) NOT NULL, phone VARCHAR(40) NOT NULL, email VARCHAR(120) NOT NULL, address VARCHAR(300) NOT NULL); -- 创建客户表用于原生 JDBC 和 JdbcTemplate。 
CREATE TABLE IF NOT EXISTS pet_orders (id BIGINT AUTO_INCREMENT PRIMARY KEY, customer_name VARCHAR(80) NOT NULL, phone VARCHAR(40) NOT NULL, total_amount DECIMAL(10,2) NOT NULL, status VARCHAR(40) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP); -- 创建订单表用于 JPA 和 Hibernate。 
CREATE TABLE IF NOT EXISTS order_items (id BIGINT AUTO_INCREMENT PRIMARY KEY, order_id BIGINT NOT NULL, product_id BIGINT NOT NULL, product_name VARCHAR(120) NOT NULL, quantity INT NOT NULL, price DECIMAL(10,2) NOT NULL); -- 创建订单明细表用于 JPA 一对多关系。 
